
const ZAI = require('z-ai-web-dev-sdk');
async function main() {
  const zai = await ZAI.default.create();
  const resp = await zai.chat.completions.createVision({
    messages: [{role:'user',content:[{type:'text',text:'Read ALL text visible in this image. What AWS page is this? What instance types, pricing, or billing info does it show?'},{type:'image_url',image_url:{url:'data:image/jpeg;base64,'}}]}],
    thinking:{type:'disabled'}
  });
  console.log(resp.choices[0]?.message?.content);
}
main().catch(e=>console.error(e.message));
